package se.medbo.examplatform.ai.generation;
import jakarta.validation.Valid;import jakarta.validation.constraints.*;import java.util.List;import java.util.Map;import java.util.UUID;import org.springframework.http.HttpStatus;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/internal/v1/knowledge-fact-generation")
final class GenerationController {private final GenerationJobService service;GenerationController(GenerationJobService service){this.service=service;}
 record Create(@NotNull UUID sourceId,@NotBlank String sourceTitle,@NotBlank String sourceContent,@Pattern(regexp="^[a-f0-9]{64}$")String sourceContentChecksum,@NotNull UUID learningObjectiveId,@NotBlank String learningObjectiveTitle,@NotBlank String requestedBy,@Min(1)@Max(20)int requestedCount,@NotBlank String language,String editorialInstruction,@NotBlank String idempotencyKey){GenerationJobService.Create input(){return new GenerationJobService.Create(sourceId,sourceTitle,sourceContent,sourceContentChecksum,learningObjectiveId,learningObjectiveTitle,requestedBy,requestedCount,language,editorialInstruction,idempotencyKey);}}
 record Edit(@NotBlank String text,@PositiveOrZero long version){}record Reject(String reason,@PositiveOrZero long version){}record Accept(@NotNull UUID knowledgeFactId,@NotBlank String acceptedBy,@PositiveOrZero long version){}
 @PostMapping("/jobs")@ResponseStatus(HttpStatus.ACCEPTED)Map<String,Object>create(@Valid@RequestBody Create r){return service.create(r.input());}@GetMapping("/jobs/{id}")Map<String,Object>get(@PathVariable UUID id){return service.get(id);}@PostMapping("/jobs/{id}/cancel")Map<String,Object>cancel(@PathVariable UUID id){return service.cancel(id);}@GetMapping("/jobs/{id}/proposals")List<Map<String,Object>>proposals(@PathVariable UUID id){return service.proposals(id);}@GetMapping("/proposals/{id}")Map<String,Object>proposal(@PathVariable UUID id){return service.proposal(id);}@PatchMapping("/proposals/{id}")Map<String,Object>edit(@PathVariable UUID id,@Valid@RequestBody Edit r){return service.edit(id,r.text(),r.version());}@PostMapping("/proposals/{id}/reject")Map<String,Object>reject(@PathVariable UUID id,@Valid@RequestBody Reject r){return service.reject(id,r.reason(),r.version());}@PostMapping("/proposals/{id}/accepted")Map<String,Object>accept(@PathVariable UUID id,@Valid@RequestBody Accept r){return service.markAccepted(id,r.knowledgeFactId(),r.acceptedBy(),r.version());}}
